"""
mkt-context layer — 1 Corinthians chapters 12–14
Output: data/commentary/mkt-context/1corinthians.json
Run: python3 scripts/zc-context-1corinthians-12-14.py
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys — safe to re-run.
    # CHANGE? If commentary JSON structure changes from {ch:{v:html}}, update this traversal.
    # VERIFY: Re-running the script should produce identical output.
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW = {
  "12": {
    "1": "Pneumatika (spiritual things/gifts): the Corinthians had written to Paul about ta pneumatika — spiritual manifestations. The term was broader than charismata; it covered the whole range of Spirit-given experiences and abilities. In Corinth's religiously competitive environment, pneumatic demonstrations were status markers.",
    "2": "Former pagan experience of ecstasy: Paul reminds them that before their conversion they were led away (apagomenoi, driven, a verb used of prisoners being led to execution) to mute idols as the Spirit moved them. Ecstatic speech occurred in Greek religion — the Pythia at Delphi and Dionysiac rituals both featured trance-states and inspired utterance.",
    "3": "Jesus is Lord as the criterion: the test of authentic Spirit-speech is the content of the confession. Kyrios Iesous (Jesus is Lord) was the foundational Christian confession. In a Roman context, calling someone Kyrios (Lord) carried political weight — the Caesar was also addressed as kyrios. The Christian confession implicitly relativized all other lordships.",
    "4": "Charismata, diakonia, energemata: Paul uses three different Greek words for the Spirit's gifts — charismata (grace-gifts), diakoniai (services, ministries), energemata (workings, operations). The same Spirit, Lord, and God undergird all three — a triadic structure that later informed trinitarian theology.",
    "5": "One Lord, many ministries: the variety of diakoniai (ministries/services) reflects the diversity of the church's service in the world. Diakonia was the term for humble table-service (Acts 6:1-6) that Paul applies broadly to all forms of Christian ministry.",
    "6": "God works all in all (ta panta en pasin): the comprehensive phrase anticipates 15:28 where God becomes all in all at the eschaton. Here it describes the divine energizing behind every gift — the community's diversity of gifts reflects God's own inexhaustible generosity.",
    "7": "The common good (sympheron): each gift is given pros to sympheron — for what is mutually beneficial, for the benefit of the whole. Sympheron was a technical term in Greek political philosophy for policies that advanced the common welfare of the polis (city-state). Paul applies the civic virtue of common good to the church assembly.",
    "8": "Word of wisdom and word of knowledge: sophia (wisdom) and gnosis (knowledge) were the terms the Corinthian elite prized — they had claimed these as their spiritual badges of honor in chapters 1-4. Paul acknowledges these as genuine Spirit-gifts but immediately embeds them in a longer list that relativizes their special status.",
    "9": "Faith and healings: the faith (pistis) here is not saving faith but the gift of miracle-working faith — the confidence to pray for the impossible (Matt 17:20; 21:21). Healings (iamata) were among the most prominent features of early Christian communities, continuing the healing ministry of Jesus.",
    "10": "Miracles, prophecy, discernment: dynameis (miraculous workings) were demonstrations of divine power that confirmed the gospel proclamation (Rom 15:19; 2 Cor 12:12). Prophecy (prophēteia) was intelligible Spirit-inspired speech for edification; discernment of spirits (diakriseis pneumatōn) evaluated whether prophetic utterances came from the Holy Spirit or other sources.",
    "11": "The Spirit distributes as he wills (kathōs bouletai): the sovereign distribution of gifts by the Spirit's own will undercuts the Corinthian competition for particular gifts. No believer earns or merits a charism; the Spirit's freedom in distributing is absolute.",
    "13": "One body, many members — the political analogy: the body politic metaphor was well-established in Greco-Roman political rhetoric. Livy (2.32) preserves the fable of Menenius Agrippa, who reconciled Rome's plebs and patricians by the parable of the stomach and the body's members. Seneca (Epistles 95.52) develops the body metaphor for humanity's mutual obligations. Paul adapts the stock rhetorical device for the church.",
    "14": "The body is not one member but many: Paul's point directly counters the Corinthian tendency to privilege the few members with spectacular gifts (especially tongues). The analogy is chosen because it makes inequality of function compatible with equality of belonging.",
    "15": "If the foot says it is not part of the body: the imagined dialogue among body parts was a rhetorical device in Hellenistic diatribe style. The diatribe was a popular philosophical lecturing technique that used imagined objectors to advance the argument.",
    "16": "If the ear says it is not part of the body: the repetition of the illustration reinforces the point through accumulation — a standard feature of ancient oral rhetoric. Repetition with variation was a teaching tool for communities that heard texts read aloud rather than read them privately.",
    "17": "If the whole body were an eye: the reductio ad absurdum — a body composed of only one sense-organ would be grotesque and nonfunctional. The argument from absurdity was a standard logical device in Hellenistic philosophical discourse.",
    "18": "God arranged the members as he chose: the divine sovereignty in arranging the body mirrors v.11 (the Spirit distributes as he wills). The church's diversity is not accidental social evolution but intentional divine design.",
    "19": "If all were one member: the singular undifferentiated body is no body at all. The argument moves from the grotesque (all eye, v.17) to the impossible (one undifferentiated member) — pressing the Corinthians to see diversity as essential rather than problematic.",
    "20": "Many members, one body: the thesis stated simply after the extended elaboration. The repetition of the main point (many/one) frames the whole section and prepares for the application to weaker and stronger members.",
    "21": "The eye cannot say to the hand it has no need: the second half of the body metaphor addresses the opposite error — not the inferior member doubting its value, but the superior member dismissing the inferior as unnecessary. In Corinth, the gifted elite were apparently devaluing those with less spectacular gifts.",
    "22": "The weaker members are indispensable (anankaia): the Greek word anankaia (necessary, indispensable) is the same root as anankē (necessity) used in 9:16 for Paul's compulsion to preach. The apparently weak members are not merely tolerated — they are necessary to the body's completeness.",
    "23": "Greater honor to lesser members: inverting the Roman social convention where honor accrued to status. In the Roman body politic, senators received greater honor than artisans; the wealthy patron received more honor than the freedman. Paul reverses the honor economy of Corinthian society.",
    "24": "God has so composed the body, giving greater honor to the part that lacked it — divine action in social ordering: the honor-redistribution in the church is not a merely human ethical choice but a reflection of how God has ordered the body. This theological grounding gives the ethic its binding force.",
    "25": "No division (schisma) in the body: the word schisma returns from 1:10 and 11:18. The body-metaphor is deployed precisely to heal the schismata that have fractured the Corinthian congregation — unity is the telos of the whole discussion.",
    "26": "If one member suffers, all suffer: the organic interconnectedness of the body means that individual pain is communal pain. Stoic philosophy taught a version of this — Seneca (On Benefits 4.18) argued that injuring one person injured the whole human community. Paul applies it to the specific community of the church.",
    "27": "You are the body of Christ and individually members of it: the direct application after the extended analogy. The church at Corinth — fractured, competitive, divided — is told that it is the body of Christ. The indicative precedes and grounds the imperative.",
    "28": "Apostles, prophets, teachers, then miracles, healings, helps, administrations, tongues: the list places the intelligible ministries (apostles, prophets, teachers) first and tongues last — a deliberate ordering that prioritizes edifying speech over spectacular experience. Helps (antilēmpseis) and administrations (kybernēseis, steering, governance) are the quiet practical gifts that rarely received honor in Corinth.",
    "29": "Are all apostles? — the rhetorical questions: the series of questions in vv.29-30 all expect the answer no. The point is that the Spirit does not give every gift to every person — diversity is structural, not a sign of deficiency.",
    "30": "Do all speak in tongues? — the governing question of the chapter: the answer is clearly no, which relativizes tongues as one gift among many rather than the supreme evidence of Spirit-possession as some Corinthians apparently held.",
    "31": "Earnestly desire the greater gifts — and the more excellent way: the transition verse that opens chapter 13. The greater gifts are the intelligible ones (prophecy above tongues) but even greater is the way of agapē that undergirds all gifts. The word hodos (way) was used for the Christian movement itself in Acts (Acts 9:2; 19:9, 23).",
  },
  "13": {
    "1": "Tongues of men and of angels: the tradition of angelic languages appears in Jewish apocalyptic — the Testament of Job 48-50 describes the daughters of Job speaking in angelic dialects after receiving heavenly sashes. The Songs of the Sabbath Sacrifice from Qumran describe angelic liturgy. Paul may be granting the Corinthians their highest possible claim for tongues to show that even this is worthless without love.",
    "2": "Move mountains: the hyperbolic faith that moves mountains echoes the dominical saying (Matt 17:20; 21:21). The allusion places Paul's teaching in line with Jesus's own sayings about faith and makes the illustration recognizable to those who knew the Jesus tradition.",
    "3": "Give away all possessions and surrender the body: the two extremes of material self-denial — total charity and ultimate self-sacrifice. Both were recognizable ideals in the ancient world: Cynic philosophers practiced radical poverty; martyrdom was the ultimate self-giving. Paul says even these avail nothing without agapē.",
    "4": "Patience (makrothymia) and kindness (chrēstotēs): the two opening attributes describe agapē in relational terms — patience with people rather than circumstances (makrothymia, longsuffering) and active kindness toward them. Both appear in the fruit of the Spirit list (Gal 5:22) and are used of God's own character (Rom 2:4).",
    "5": "Love does not seek its own (ta heautēs): the selflessness of agapē directly counters the Corinthian pattern of seeking one's own advantage in spiritual gifts, in food, and in litigation. The phrase echoes Paul's own practice described in 10:33 (not seeking my own advantage).",
    "6": "Love does not rejoice in wrongdoing but in truth: the pairing of wrongdoing (adikia) and truth (alētheia) has philosophical resonance — in Greek ethics, adikia was the fundamental vice of injustice, and alētheia was the virtue of honesty that underpins all right relations. Love refuses to take pleasure in another's failure or the triumph of injustice.",
    "7": "Bears, believes, hopes, endures all things: the four stegei/pisteuei/elpizei/hypomenei verbs create a climactic list. Stegō (bear, cover) appears in the context of not exposing others' failings; hypomenō (endure, remain under) was the Stoic virtue of patient perseverance under hardship. Love incorporates and transcends the Stoic ideals.",
    "8": "Love never fails (agapē oudepote piptei): piptō (fall, fail, come to an end) — love will not fall or come to nothing at the eschaton when all partial gifts cease. The three gifts named — prophecy, tongues, knowledge — are precisely the ones the Corinthians most valued.",
    "9": "We know in part, we prophesy in part: the two gifts the Corinthians prized most — knowledge and prophecy — are both partial (ek merous). The honest acknowledgment of epistemological limitation counters the Corinthian gnōsis-boast of superior knowledge.",
    "10": "When the perfect (to teleion) comes: to teleion (the complete, the mature, the fully realized) has been interpreted as the completion of the NT canon (cessationist reading), the Second Coming (eschatological reading), or mature corporate spiritual life (developmental reading). The contrast with ek merous (partial) favors an eschatological reading: the fullness of the age to come replaces the partial gifts of the present age.",
    "11": "When I was a child: the autobiographical illustration from personal developmental history was a common rhetorical device. The analogy maps onto the ages: childhood corresponds to the present age with its partial gifts; adulthood to the eschatological fullness. Paul uses the first person to avoid condescension.",
    "12": "Seeing through a mirror dimly (di esoptrou en ainigmati): esoptron (mirror) in the ancient world was polished bronze or silver, not glass — it produced a real but imperfect and indirect image. Ainigma (riddle, enigma) was used for indirect or obscure speech as opposed to direct speech (prosōpon pros prosōpon, face to face — as Moses spoke with God in Num 12:8). The contrast is between indirect, mediated knowledge and direct, unmediated encounter.",
    "13": "Faith, hope, and love — the greatest is love: the triad of pistis, elpis, and agapē was already established in early Christian catechesis (1 Thess 1:3; 5:8; Gal 5:5-6; Rom 5:1-5). The listing of love as the greatest is not because faith and hope are lesser virtues, but because love alone persists into the eschatological age — faith will be sight, hope will be fulfillment, but love (as the nature of God himself) continues forever.",
  },
  "14": {
    "1": "Pursue love (diōkete tēn agapēn): the verb diōkō means to pursue, chase, even persecute — the same verb used for persecution in 15:9. Paul uses it to describe the urgency of pursuing love and the eagerness with which spiritual gifts (especially prophecy) should be desired.",
    "2": "Speaking in tongues to God, not to people: the glossolalist speaks mysteries (mystēria) in the Spirit — the content is addressed upward (to God) rather than horizontally (to the assembly). This is an important distinction for understanding the gift: it is real Spirit-enabled communication with God, not fake speech.",
    "3": "Prophecy for edification, exhortation, comfort: the three functions of prophecy — oikodomē (building up, construction), paraklēsis (exhortation, encouragement, the same root as the Holy Spirit's name Paraclete), and paramythia (consolation, comfort) — are all horizontal, community-directed functions. This is why prophecy is superior in the assembly context.",
    "4": "The one who speaks in tongues builds up himself: the edification of the individual (heauton oikodomeō) is not dismissed but subordinated. Paul affirms the personal value of tongues (v.18 I thank God I speak in tongues more than all of you) while arguing that the assembly's corporate edification takes priority.",
    "5": "I wish you all spoke in tongues: Paul expresses a genuine desire for all to have the gift, showing he does not denigrate tongues. The comparative (mallon de hina prophēteuēte — but even more that you prophesy) is the key: prophecy is relatively more valuable for the assembly's purpose.",
    "6": "Revelation, knowledge, prophecy, or teaching: the four forms of intelligible Spirit-communication that benefit the assembly. All four involve conveying content that can be understood and received — the criterion is comprehensibility.",
    "7": "Flute and harp giving indistinct notes: the musical illustration was accessible to any Corinthian who had attended civic festivals, theater, or athletic competitions, all of which featured instrumental music. An instrument that played only random notes without melody communicated nothing.",
    "8": "The uncertain trumpet sound: the military analogy of the trumpet (salpinx) was universally understood in the Roman empire. The salpinx sounded the advance, retreat, and different battle maneuvers — each call had a specific meaning. An unclear trumpet call was potentially fatal in battle.",
    "9": "Intelligible words with the tongue: the argument from analogy lands on the specific point: speaking in tongues without interpretation is like an indistinct trumpet — the hearer cannot respond appropriately because the message is inaccessible.",
    "10": "Many kinds of voices (phōnai) in the world: Paul grants the existence of many languages (phōnai, sounds, voices) — each meaningful to its native speakers. The diversity of human languages was noted by ancient writers (Josephus, Antiquities 1.5.1; Philo, On the Confusion of Tongues).",
    "11": "A foreigner (barbaros) to the speaker: barbaros was the Greek term for anyone whose language sounded like babble (bar-bar) to Greek ears. The foreigner analogy is pointed: the tongues-speaker without interpretation is reducing the assembly to a crowd of mutual barbarians, unable to communicate.",
    "12": "Seek to excel in building up the church: the Corinthians' zeal for pneumatika (spiritual manifestations) is acknowledged and redirected. The same energy should be applied to gifts that build up (oikodomē) the ekklēsia — the civic-assembly term now applied to the gathered church.",
    "13": "Pray to interpret: the tongue-speaker should pray for the gift of interpretation (diermēneuō, to translate/explain across language) so that their private communion with God can become public edification for the assembly.",
    "14": "My spirit prays but my mind is unfruitful: pneuma and nous (spirit and mind) in distinction — in tongues the spirit (the deep center of the person animated by the Holy Spirit) prays, but the nous (rational faculty) contributes nothing. The nous remains akarpos (without fruit, unproductive) for the purpose of communal edification.",
    "15": "Pray with the spirit and with the mind also: the both/and solution — Paul does not advocate abandoning tongues but insisting that mind-involving intelligible prayer and song accompany or complement Spirit-prayer. The synagogue practice of intelligible liturgical prayer informs this instinct.",
    "16": "The one in the position of an outsider (idiōtēs): the idiōtēs in Corinthian context was probably the uninitiated visitor or the believer without the gift of tongues — someone who occupies the layperson's position relative to the specialist. In Greek civic life, idiōtēs was the private citizen as opposed to the public official.",
    "17": "You are giving thanks well enough but the other person is not built up: the eucharistia (thanksgiving, giving thanks) in tongues may be genuine and beautiful, but its benefit is limited to the one praying. Community discernment requires an evaluative standard beyond individual sincerity.",
    "18": "I speak in tongues more than all of you: Paul's remarkable disclosure — he has the gift of tongues more abundantly than any Corinthian. This disarms the argument that his preference for prophecy stems from envy or deficiency. He speaks from experience, not ignorance.",
    "19": "Five words with the mind vs. ten thousand in tongues: the numerical contrast (pente logous kata noun vs. myrioys en glōssē) dramatizes the principle. The number 10,000 (myrioi) was the Greek word for an uncountable multitude — the contrast between meaningful speech and unmeasurable meaningless speech is stark.",
    "20": "Do not be children in your thinking: the contrast between nēpioi (infants, childlike) in thinking and teleios (mature, complete) in thinking echoes the wisdom tradition. Sirach 3:9-11 and Philo use similar contrasts. The Corinthians' attraction to spectacular gifts reflects an immature evaluation of spiritual worth.",
    "21": "Citing Isaiah 28:11-12: Paul cites the LXX of Isaiah 28 (with other lips and another tongue God will speak to this people). In context, Isaiah prophesied Assyrian invasion as God's judgment on an unbelieving Israel — the foreign tongue of the Assyrian conqueror was a sign of judgment. Paul applies this typologically: tongues in the assembly function as a sign for unbelievers (a sign of divine presence that, without interpretation, judges rather than converts).",
    "22": "Tongues as a sign for unbelievers, prophecy for believers: Paul's distinction is counterintuitive at first reading but follows from Isaiah 28. Tongues without interpretation confront the unbeliever with an incomprehensible divine speech (a sign of judgment); prophecy speaks the divine word intelligibly for those who already believe.",
    "23": "If the whole church comes together and all speak in tongues: the scenario Paul imagines — an outsider (idiōtēs) or unbeliever entering an assembly of unintelligible ecstatic speech — would result in the verdict that the Christians are out of their minds (mainomai, the same word used of Dionysiac frenzy). The church's public witness is at stake.",
    "24": "If all prophesy and an unbeliever enters: the contrasting scenario — intelligible prophetic speech convicts (elenchō, convict, expose), examines (anakrinetai), reveals the secrets of the heart, causing the visitor to fall on his face, worship God, and declare that God is truly among you. The missionary and evangelistic value of intelligible worship is the practical argument for prophecy.",
    "25": "God is truly among you (ontōs en hymin estin): the declaration of the converted visitor echoes OT theophanies — the sense of actual divine presence manifested in the assembly. This is the goal of corporate worship: an encounter with the living God that transforms.",
    "26": "When you come together, each one has a psalm, a teaching, a revelation, a tongue, an interpretation: the description of an early Christian assembly — participatory, diverse, Spirit-animated. This is not a structured liturgy but a Spirit-ordered gathering where multiple contributions are expected and evaluated.",
    "27": "Two or at most three in tongues, and each in turn: Paul imposes structure on the spontaneous gift. The limitation to two or three, the requirement of sequential (not simultaneous) speech, and the requirement of interpretation bring order without suppressing the gift.",
    "28": "If there is no interpreter, let the tongue-speaker be silent: the silence is not permanent but situational — without the interpreter function, tongues cannot serve the assembly's edification. The silent tongue-speaker may still pray inwardly (laleito de heautō kai tō theō — let him speak to himself and to God).",
    "29": "Two or three prophets, and let the others weigh what is said: the same structural limitation applies to prophecy. The diakrinetōsan (discern, judge, weigh) is a communal function — the assembly evaluates prophetic utterances rather than receiving them uncritically. This prophetic testing was a feature of Jewish prophetic practice (Deut 18:21-22; 1 John 4:1).",
    "30": "If a revelation comes to someone else sitting: the dynamic assembly allows for spontaneous prophetic utterance during the meeting. The seated prophet may receive a revelation; the standing prophet yields to allow the new word to be spoken. The process is orderly but flexible.",
    "31": "All may prophesy one by one: the democratic access to prophetic speech (one by one, kata hena) reflects the Joel 2:28 promise (your sons and daughters will prophesy). Paul's assembly is not monopolized by a single charismatic leader.",
    "32": "The spirits of prophets are subject to the prophets: the pneumata tōn prophētōn (the spiritual endowments/impulses of prophets) are under the prophets' own self-control. This directly counters the claim that ecstatic possession inevitably overrides self-control — a claim made for the Delphic Pythia and Dionysiac prophets.",
    "33": "God is not a God of disorder (akatastasia) but of peace (eirēnē): the theological anchor for the entire organizational discussion. Akatastasia was the term for political and social upheaval in Hellenistic usage (Josephus, Wars 4.3.9). The church's orderly worship reflects the character of its God.",
    "34": "Women to be silent in the churches: this instruction stands in apparent tension with 11:5 (women pray and prophesy). The silence commanded here may be specific — perhaps the practice of publicly questioning or challenging prophetic utterances during the assembly, which would violate the honor of the public space. Some manuscripts place vv.34-35 after v.40, suggesting possible textual movement in the transmission.",
    "35": "If they want to learn something, let them ask their husbands at home: the home as the appropriate educational venue for women's questions reflects the Jewish synagogue practice where women and men were separated, and formal instruction was the domain of the male household head. Paul may be addressing a specific disruptive behavior in the Corinthian assembly.",
    "36": "Did the word of God originate with you? — the sharp rhetorical rebuke suggests that some Corinthians were treating their local practices as the standard for all churches. The twin questions challenge the Corinthian pretension to set the norms of Christian worship.",
    "37": "If anyone thinks he is a prophet or spiritual: those who claim prophetic or spiritual status must demonstrate it by recognizing that Paul's instructions are a command of the Lord (entolē kyriou). The test of genuine spiritual discernment is submission to apostolic authority.",
    "38": "If anyone does not recognize this, he is not recognized: the consequence of refusing Paul's teaching is not being recognized — by God, by the community, as genuinely prophetic. The passive agnoeisthai (to be unknown/unrecognized) may be a divine passive.",
    "39": "Earnestly desire to prophesy and do not forbid speaking in tongues: the balanced conclusion — prophecy is to be pursued eagerly; tongues are not to be suppressed. Paul does not eliminate tongues from the assembly but regulates them in the service of communal edification.",
    "40": "All things should be done decently and in order (euschēmonōs kai kata taxin): euschēmonōs (becomingly, properly, in a fitting manner) was a term of social propriety in Hellenistic culture — what befits a person of good standing in public. Kata taxin (according to order) is a military and organizational term. Both words come from the same civic and social world Paul and his readers inhabited.",
  }
}

if __name__ == '__main__':
    existing = load_comm('mkt-context', '1corinthians')
    merge_comm(existing, NEW)
    save_comm('mkt-context', '1corinthians', existing)
    for ch in ['12', '13', '14']:
        print(f'  ch {ch}: {len(existing.get(ch, {}))} verses')
